const raw = $input.first().json;
const msg = raw.message ?? raw.body?.message;
const text = (msg?.text || '').trim();
const chatId = String(msg?.chat?.id || '');
const staticData = $getWorkflowStaticData('global');

let intent = 'help';
let categoryQuery = '';
let marketplace = 'ES';
let maxItems = 200; // default

if (/collect\s*asin|scrape\s*asin|get\s*asin|start\s*asin|find\s*asin/i.test(text)) {
  intent = 'collect_asins';

  // Extract maxItems: number like 500, or 'unlimited' / 'all'
  const unlimitedMatch = /\b(unlimited|all|no.?limit)\b/i.test(text);
  const numMatch = text.match(/\b(\d{2,5})\b/);
  if (unlimitedMatch) {
    maxItems = 0; // 0 = unlimited
  } else if (numMatch) {
    maxItems = parseInt(numMatch[1]);
  }

  categoryQuery = text
    .replace(/collect\s*asins?|scrape\s*asins?|get\s*asins?|start\s*asin\s*collection|find\s*asins?/gi, '')
    .replace(/\bfrom\b|\bof\b|\bfor\b|\bin\b/gi, '')
    .replace(/\b(ES|UK|DE|FR|IT)\b/gi, '')
    .replace(/\b(unlimited|all|no.?limit)\b/gi, '')
    .replace(/\b\d{2,5}\b/g, '')
    .replace(/[>]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
} else if (/scrape\s*seller|seller\s*data|seller\s*info|start\s*seller|seller\s*scrap/i.test(text)) {
  intent = 'scrape_sellers';
} else if (/status|progress/i.test(text)) {
  intent = 'status';
}

const mpMatch = text.match(/\b(ES|UK|DE|FR|IT)\b/i);
if (mpMatch) marketplace = mpMatch[1].toUpperCase();

const session = staticData[chatId] || {};

return [{ json: { intent, categoryQuery, marketplace, maxItems, chatId, originalText: text, session } }];

// Parse CSV from Google Sheets and filter by query
const resp = $('Fetch Browse Nodes').item.json;
let csvText = '';
if (typeof resp === 'string') {
  csvText = resp;
} else if (typeof resp.data === 'string') {
  csvText = resp.data;
} else if (typeof resp.body === 'string') {
  csvText = resp.body;
} else {
  csvText = JSON.stringify(resp);
}

const query = ($('Parse Message').item.json.categoryQuery || '').toLowerCase().trim();
const marketplace = $('Parse Message').item.json.marketplace || 'ES';
const chatId = $('Parse Message').item.json.chatId;

if (!csvText || !query) {
  return [{ json: { matched: [], query, marketplace, chatId, count: 0, error: query ? 'No CSV data' : 'Empty query' } }];
}

const lines = csvText.replace(/\r/g, '').split('\n').filter(l => l.trim());
const allNodes = [];
const seen = new Set();

for (let i = 1; i < lines.length; i++) {
  const cols = [];
  let cur = '', inQ = false;
  for (const ch of lines[i]) {
    if (ch === '"') { inQ = !inQ; }
    else if (ch === ',' && !inQ) { cols.push(cur.trim()); cur = ''; }
    else { cur += ch; }
  }
  cols.push(cur.trim());

  const esId = (cols[1] || '').trim();
  const englishPath = (cols[5] || '').trim();
  if (!esId || !englishPath || seen.has(esId)) continue;
  seen.add(esId);

  const parts = englishPath.split(' > ').filter(Boolean);
  allNodes.push({
    id: esId,
    name: parts[parts.length - 1] || englishPath,
    path: englishPath,
    nodes: {
      ES: esId || null,
      UK: (cols[6] || '').trim() || null,
      DE: (cols[7] || '').trim() || null,
      FR: (cols[8] || '').trim() || null,
      IT: (cols[9] || '').trim() || null
    }
  });
}

const queryParts = query.split(/\s+/).filter(Boolean);

// Stem handling for singular/plural: woman->women, chairs->chair, accessories->accessor, wipes->wipe
const toStem = (w) => {
  if (w === 'woman') return 'women';
  if (w === 'men' || w === 'man') return 'men';
  if (w.endsWith('ies') && w.length > 4) return w.slice(0, -3);
  if (w.endsWith('s') && w.length > 3) return w.slice(0, -1);
  return w;
};
const stems = queryParts.map(p => toStem(p));

const stemMatch = (text, stem, orig) => text.includes(orig) || text.includes(stem);

const scoreNode = (n) => {
  const pl = (n.path || '').toLowerCase();
  const nl = (n.name || '').toLowerCase();
  let nameHits = 0, pathHits = 0;
  for (let i = 0; i < stems.length; i++) {
    if (stemMatch(nl, stems[i], queryParts[i])) nameHits++;
    if (stemMatch(pl, stems[i], queryParts[i])) pathHits++;
  }
  const totalHits = Math.max(nameHits, pathHits);
  if (totalHits === 0) return 0;
  let score = totalHits * 3;
  if (totalHits === stems.length) score += 15;
  if (nameHits === stems.length) score += 10;
  score += nameHits * 2 + pathHits;
  return score;
};

// First pass: prefer nodes where ALL stems match
let scored = allNodes
  .filter(n => n.nodes && n.nodes[marketplace])
  .map(n => ({ node: n, score: scoreNode(n) }))
  .filter(s => s.score > 0);

// If strict all-match found, keep only those; otherwise keep partial matches as fallback
const allMatch = scored.filter(s => {
  const pl = (s.node.path || '').toLowerCase();
  const nl = (s.node.name || '').toLowerCase();
  return stems.every((st, i) => stemMatch(pl, st, queryParts[i]) || stemMatch(nl, st, queryParts[i]));
});
if (allMatch.length > 0) scored = allMatch;

const finalNodes = scored
  .sort((a, b) => b.score - a.score)
  .slice(0, 20)
  .map(s => s.node);

const maxItems = $('Parse Message').item.json.maxItems ?? 200;
return [{ json: { matched: finalNodes, query, marketplace, chatId, count: finalNodes.length, maxItems } }];

const { matched, marketplace, chatId, query, maxItems } = $('Find Matching Nodes').item.json;

// ── Change this URL when deployed to Cloud Run ──────────────────────
const SCRAPER_API_URL = 'http://127.0.0.1:8080';
// ────────────────────────────────────────────────────────────────────

const MP_DOMAINS = { ES: 'amazon.es', UK: 'amazon.co.uk', DE: 'amazon.de', FR: 'amazon.fr', IT: 'amazon.it' };
const domain = MP_DOMAINS[marketplace] || 'amazon.es';
const mpLower = marketplace.toLowerCase() === 'uk' ? 'co.uk' : marketplace.toLowerCase();

let categoryUrls = matched.map(n => ({
  url: 'https://www.' + domain + '/s?rh=n:' + n.nodes[marketplace] + '&language=en',
  category_name: n.name,
  category_path: n.path
}));

// Limit categories — each yields ~20 items max
if (maxItems > 0) {
  const maxCats = Math.max(1, Math.ceil(maxItems / 20));
  categoryUrls = categoryUrls.slice(0, maxCats);
}

const apiRequest = {
  category_urls: categoryUrls,
  marketplace: mpLower,
  max_items: maxItems || 0
};

return [{ json: {
  apiRequest,
  apiUrl: SCRAPER_API_URL + '/get-asins',
  marketplace, chatId, query, maxItems,
  categoryCount: matched.length,
  categories: matched.map(n => ({ id: n.id, name: n.name, path: n.path }))
} }];

const runData = $('Start ASIN Actor').item.json;
const prev = $('Build ASIN Actor Input').item.json;
const runId = runData?.data?.id;
if (!runId) throw new Error('Apify did not return a run ID: ' + JSON.stringify(runData));
return [{ json: { runId, marketplace: prev.marketplace, chatId: prev.chatId, query: prev.query, categories: prev.categories, maxItems: prev.maxItems || 0, pollCount: 0 } }];

const runStatus = $('Check ASIN Run Status').item.json?.data?.status || 'UNKNOWN';
const ctx = $('Wait 45s — ASIN').item.json;
const pollCount = (ctx.pollCount || 0) + 1;
const timedOut = pollCount >= 40;
const isDone = ['SUCCEEDED', 'FAILED', 'ABORTED', 'TIMED-OUT'].includes(runStatus) || timedOut;
return [{ json: {
  runId: ctx.runId,
  chatId: ctx.chatId,
  query: ctx.query,
  categories: ctx.categories,
  marketplace: ctx.marketplace,
  maxItems: ctx.maxItems || 0,
  runStatus,
  pollCount,
  statusLabel: isDone ? 'done' : 'pending',
  timedOut
} }];

// Parse response from custom scraper API (/get-asins)
const apiResponse = $('Start ASIN Actor').item.json;
const prev = $('Build ASIN Actor Input').item.json;
const chatId = prev.chatId;
const maxItems = prev.maxItems || 0;

// API returns { status, total, asins: [...] }
let rawAsins = [];
if (Array.isArray(apiResponse.asins)) {
  rawAsins = apiResponse.asins;
} else if (Array.isArray(apiResponse)) {
  rawAsins = apiResponse;
}

const allAsins = [];
const asinSet = new Set();

for (const item of rawAsins) {
  const asin = String(item.asin || '').trim().toUpperCase();
  if (asin && asin.length >= 8 && !asinSet.has(asin)) {
    asinSet.add(asin);
    allAsins.push({
      asin,
      title: item.title || '',
      category: item.category || item.category_name || '',
      categoryPath: item.category_path || ''
    });
  }
}

const asins = (maxItems > 0) ? allAsins.slice(0, maxItems) : allAsins;

const sessionData = {
  asinsJson: JSON.stringify(asins),
  asinCount: asins.length,
  marketplace: prev.marketplace,
  categoryQuery: prev.query,
  collectedAt: new Date().toISOString()
};

// ── Persist session in workflow static data (survives between executions) ──
const staticData = $getWorkflowStaticData('global');
staticData[chatId] = sessionData;

return [{ json: {
  chatId,
  ...sessionData,
  maxItems,
  previewAsins: asins.slice(0, 5)
} }];

// Read session from workflow static data (written by Store ASINs node)
const chatId = $('Parse Message').item.json.chatId;
const staticData = $getWorkflowStaticData('global');
const session = staticData[chatId];

if (!session || !session.asinsJson) {
  return [{ json: { asins: [], asinCount: 0, chatId, marketplace: '', categoryQuery: '' } }];
}

let asins = [];
try { asins = JSON.parse(session.asinsJson || '[]'); } catch(e) { asins = []; }

return [{ json: {
  asins,
  asinCount: asins.length,
  marketplace: session.marketplace || '',
  categoryQuery: session.categoryQuery || '',
  chatId
} }];

const session = $('Parse Loaded Session').item.json;
const marketplace = session.marketplace || 'ES';

// ── Change this URL when deployed to Cloud Run ──────────────────────
const SCRAPER_API_URL = 'http://127.0.0.1:8080';
// ────────────────────────────────────────────────────────────────────

const mpLower = marketplace.toLowerCase() === 'uk' ? 'co.uk' : marketplace.toLowerCase();
const asins = session.asins || [];

const apiRequest = {
  asins: asins.map(a => ({
    asin: a.asin,
    category: a.category || '',
    category_path: a.categoryPath || ''
  })),
  marketplace: mpLower
};

return [{ json: {
  apiRequest,
  apiUrl: SCRAPER_API_URL + '/scrape-from-asins',
  marketplace, chatId: session.chatId,
  categoryQuery: session.categoryQuery,
  categories: session.categories || [],
  asins
} }];

const runData = $('Start Seller Actor').item.json;
const prev = $('Build Seller Actor Input').item.json;
const runId = runData?.data?.id;
if (!runId) throw new Error('Apify did not return a seller run ID: ' + JSON.stringify(runData));
return [{ json: { runId, marketplace: prev.marketplace, chatId: prev.chatId, categoryQuery: prev.categoryQuery, categories: prev.categories, asins: prev.asins, pollCount: 0 } }];

const runStatus = $('Check Seller Run Status').item.json?.data?.status || 'UNKNOWN';
const ctx = $('Wait 60s — Seller').item.json;
const pollCount = (ctx.pollCount || 0) + 1;
const timedOut = pollCount >= 60;
const isDone = ['SUCCEEDED', 'FAILED', 'ABORTED', 'TIMED-OUT'].includes(runStatus) || timedOut;
return [{ json: {
  runId: ctx.runId,
  chatId: ctx.chatId,
  categoryQuery: ctx.categoryQuery,
  categories: ctx.categories,
  asins: ctx.asins,
  marketplace: ctx.marketplace,
  runStatus,
  pollCount,
  statusLabel: isDone ? 'done' : 'pending',
  timedOut
} }];

// Parse response from custom scraper API (/scrape-from-asins)
const apiItems = $('Start Seller Actor').all();
const prev = $('Build Seller Actor Input').item.json;

const asinMeta = {};
for (const a of (prev.asins || [])) asinMeta[a.asin] = { category: a.category, categoryPath: a.categoryPath };

// API returns { status, total, successful, failed, results: [...] }
let items = [];
if (apiItems.length === 1) {
  const resp = apiItems[0].json;
  if (Array.isArray(resp.results)) {
    items = resp.results;
  } else if (Array.isArray(resp)) {
    items = resp;
  }
} else {
  items = apiItems.map(i => i.json);
}

const sellers = items.map(item => {
  const asin = item.asin || '';
  const meta = asinMeta[asin] || {};
  const catPath = item.category_path || meta.categoryPath || prev.categoryQuery || 'General';
  const pathParts = catPath.split(' > ');
  const mainCategory = pathParts[0] || 'General';
  const subCategory = pathParts.slice(1).join(' > ') || mainCategory;

  return {
    asin,
    marketplace: prev.marketplace || 'ES',
    category: item.category || meta.category || '',
    category_path: catPath,
    main_category: mainCategory,
    sub_category: subCategory,
    business_name: item.business_name || '',
    business_address: item.address || item.raw_info || '',
    email: item.email || '',
    phone: item.phone || '',
    vat_number: item.vat_number || '',
    seller_url: item.storefront_url || '',
    status: item.status === 'success' ? 'SUCCESS' : (item.status || 'NO_DATA')
  };
}).filter(s => s.asin);

const groups = {};
for (const s of sellers) {
  const key = s.main_category + '|||' + s.sub_category;
  if (!groups[key]) groups[key] = { mainCategory: s.main_category, subCategory: s.sub_category, rows: [] };
  groups[key].rows.push(s);
}

return [{ json: {
  sellers,
  groups: Object.values(groups),
  totalSellers: sellers.length,
  chatId: prev.chatId,
  marketplace: prev.marketplace,
  categoryQuery: prev.categoryQuery
} }];

const data = $input.first().json;
const groups = data.groups || [];
if (groups.length === 0) {
  return [{ json: { ...data, mainCategory: 'General', subCategory: 'General', rows: data.sellers || [] } }];
}
return groups.map(g => ({ json: { ...g, chatId: data.chatId, marketplace: data.marketplace, categoryQuery: data.categoryQuery, totalSellers: data.totalSellers } }));

const mainFolderId = $input.first().json.id;
const groupData = $('Split by Category Group').item.json;
return [{ json: { ...groupData, mainFolderId } }];

const subFolderId = $input.first().json.id;
const groupData = $('Attach Main Folder ID').item.json;
return [{ json: { ...groupData, subFolderId } }];

const spreadsheetId = $('Create Spreadsheet').item.json.spreadsheetId;
const groupData = $('Attach Sub Folder ID').item.json;
const rows = groupData.rows || [];

if (rows.length === 0) {
  return [{ json: { spreadsheetId, isEmpty: true, chatId: groupData.chatId, mainCategory: groupData.mainCategory, subCategory: groupData.subCategory, totalSellers: groupData.totalSellers, marketplace: groupData.marketplace } }];
}

return rows.map(row => ({
  json: {
    spreadsheetId,
    chatId: groupData.chatId,
    mainCategory: groupData.mainCategory,
    subCategory: groupData.subCategory,
    totalSellers: groupData.totalSellers,
    marketplace: groupData.marketplace,
    ASIN: row.asin,
    Marketplace: row.marketplace,
    Category: row.category,
    'Category Path': row.category_path,
    'Business Name': row.business_name,
    'Business Address': row.business_address,
    Email: row.email,
    Phone: row.phone,
    'VAT Number': row.vat_number,
    'Seller URL': row.seller_url,
    Status: row.status
  }
}));

const items = $input.all();
const first = items[0]?.json || {};
return [{ json: {
  chatId: first.chatId,
  totalSellers: first.totalSellers,
  marketplace: first.marketplace,
  mainCategory: first.mainCategory,
  subCategory: first.subCategory,
  spreadsheetId: first.spreadsheetId
} }];
